// Flora → 미니앱 태스크 데이터 변환
const body = $input.first().json.body || $input.first().json;

// 필수 필드
const title = (body.title || '').trim();
if (!title) {
  return [{ json: { ok: false, error: 'title is required' } }];
}

// 날짜 처리 (자연어→ISO)
let dueAt = body.dueAt || null;
if (dueAt && !/T/.test(dueAt)) {
  dueAt = dueAt + 'T23:59:59+09:00';
}

const taskPayload = {
  title: title,
  priority: body.priority || 'p3',
  assignee: body.assignee || null,
  status: 'todo',
  relatedProject: body.project || null
};

if (dueAt) taskPayload.dueAt = dueAt;
if (body.description) {
  taskPayload.detailsJson = JSON.stringify({ description: body.description });
}

// 텔레그램 알림용 정보
const chatId = body.chatId || '7713811206';
const senderName = body.senderName || '플로라';

return [{ json: { taskPayload, chatId, senderName, originalTitle: title } }];

// 생성 결과 처리 + 텔레그램 메시지 생성
const prev = $('데이터 변환').first().json;
const response = $input.first().json;
const statusCode = response.statusCode || response.status || 200;
const resBody = response.body || response;

let ok = false;
let taskId = null;
let msg = '';

if (statusCode >= 200 && statusCode < 300 && resBody.ok) {
  ok = true;
  taskId = resBody.task ? resBody.task.id : null;
  const t = prev.taskPayload;
  msg = '\u2705 업무가 등록되었습니다\n\n';
  msg += '\u{1F4CB} ' + prev.originalTitle + '\n';
  if (t.dueAt) {
    const d = new Date(t.dueAt);
    const m = d.getMonth()+1;
    const day = d.getDate();
    const h = d.getHours();
    const min = String(d.getMinutes()).padStart(2,'0');
    msg += '\u{1F4C5} ' + m + '/' + day;
    if (h < 23) msg += ' ' + h + ':' + min;
    msg += '\n';
  }
  if (t.assignee) msg += '\u{1F464} ' + t.assignee + '\n';
  if (t.relatedProject) msg += '\u{1F3AF} ' + t.relatedProject + '\n';
  msg += '\n\u{1F517} mini.pressco21.com 에서 확인';
} else {
  msg = '\u274C 태스크 등록 실패: ' + (resBody.error || JSON.stringify(resBody));
}

return [{ json: { ok, taskId, message: msg, chatId: prev.chatId } }];
